mapper.insert:
insert into share (shareId, userId, shareType, content,
  imgUrl, linkUrl, shareChannel, createdDate
  )
values (#{shareId,jdbcType=BIGINT}, #{userId,jdbcType=BIGINT},#{shareType,jdbcType=TINYINT}, #{content,jdbcType=VARCHAR},
  #{imgUrl,jdbcType=VARCHAR},#{linkUrl,jdbcType=VARCHAR}, #{shareChannel,jdbcType=TINYINT}, #{createdDate,jdbcType=TIMESTAMP}
  )

mapper.select:
SELECT shareType, content, imgUrl,linkUrl, shareChannel,title,
 ui.nickname,ui.headImgUrl
 FROM share left join user_info ui on ui.userId=#{userId}
 WHERE shareType = #{shareType}
